// // This module implements a 2-bit counter that decrements on each clock cycle when the enable signal is high and resets to zero on the falling edge of the clock when the reset signal is high.
module counter_2bit(
    input  clk,
    input  rst,
    input  en,
    output reg [1:0] count
);

always @(posedge clk) begin
    if (rst)
        count <= 2'b00;
    else if (en)
        count <= count + 1;
end

endmodule
